CREATE OR REPLACE FUNCTION pgstac.get_or_create_fragment(content jsonb, _collection text, excluded_keys text[] DEFAULT '{id,geometry,collection,type}'::text[])
 RETURNS bigint
 LANGUAGE plpgsql
AS $function$
DECLARE
    frag_content jsonb;
    frag_hash    text;
    frag_id      bigint;
BEGIN
    IF content IS NULL OR _collection IS NULL THEN
        RETURN NULL;
    END IF;

    frag_content := extract_fragment(content, excluded_keys);
    frag_hash    := pgstac_hash_fragment(frag_content);

    -- Insert-first: one round trip when the fragment is new.
    WITH ins AS (
        INSERT INTO item_fragments (collection, hash, content)
        VALUES (_collection, frag_hash, frag_content)
        ON CONFLICT (collection, hash) DO NOTHING
        RETURNING id
    )
    SELECT id INTO frag_id FROM ins;

    -- Fallback SELECT: one extra round trip only on the conflict path.
    IF frag_id IS NULL THEN
        SELECT id INTO frag_id
        FROM item_fragments
        WHERE collection = _collection AND hash = frag_hash;
    END IF;

    RETURN frag_id;
END;
$function$
;

CREATE OR REPLACE FUNCTION pgstac.items_delete_log_trigger()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
BEGIN
    INSERT INTO items_deleted_log (
        item_id,
        collection,
        partition,
        datetime,
        end_datetime,
        content_hash
    )
    SELECT
        old_rows.id,
        old_rows.collection,
        (partition_name(old_rows.collection, old_rows.datetime)).partition_name,
        old_rows.datetime,
        old_rows.end_datetime,
        old_rows.content_hash
    FROM old_rows;

    RETURN NULL;
END;
$function$
;

CREATE OR REPLACE FUNCTION pgstac.items_touch_triggerfunc()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
BEGIN
    NEW.pgstac_updated_at := now();
    NEW.content_hash := encode(sha256(content_hydrate(NEW)::text::bytea), 'hex');
    RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION pgstac.jsonb_field_rows(data jsonb, parent_path text DEFAULT ''::text, max_depth integer DEFAULT 20)
 RETURNS TABLE(path text, is_leaf boolean, value_kind text)
 LANGUAGE plpgsql
 IMMUTABLE PARALLEL SAFE
AS $function$
DECLARE
    k text;
    v jsonb;
    current_path text;
    jtype text;
BEGIN
    IF data IS NULL OR max_depth <= 0 THEN
        RETURN;
    END IF;
    jtype := jsonb_typeof(data);
    IF jtype = 'object' THEN
        FOR k, v IN SELECT * FROM jsonb_each(data) LOOP
            current_path := CASE WHEN parent_path = '' THEN k ELSE parent_path || '.' || k END;
            IF jsonb_typeof(v) IN ('object', 'array') THEN
                RETURN QUERY SELECT current_path, FALSE, jsonb_typeof(v);
                RETURN QUERY SELECT * FROM jsonb_field_rows(v, current_path, max_depth - 1);
            ELSE
                RETURN QUERY SELECT current_path, TRUE, jsonb_typeof(v);
            END IF;
        END LOOP;
    ELSIF jtype = 'array' THEN
        -- Walk array elements (e.g. arrays of nested objects); arrays of scalars
        -- are already handled as leaves in the object branch above.
        FOR v IN SELECT jsonb_array_elements(data) LOOP
            IF jsonb_typeof(v) = 'object' THEN
                RETURN QUERY SELECT * FROM jsonb_field_rows(v, parent_path, max_depth - 1);
            END IF;
        END LOOP;
    END IF;
END;
$function$
;

CREATE OR REPLACE FUNCTION pgstac.name_search(_search jsonb, _name text, _metadata jsonb DEFAULT '{}'::jsonb)
 RETURNS searches
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    named searches%ROWTYPE;
BEGIN
    named := search_query(_search, false, _metadata);
    UPDATE searches
    SET
        name = _name,
        lastused = now(),
        usecount = searches.usecount + 1
    WHERE hash = named.hash
    RETURNING * INTO named;

    IF named IS NULL THEN
        RAISE EXCEPTION 'Could not name search for input: %', _search;
    END IF;

    RETURN named;
END;
$function$
;

CREATE OR REPLACE FUNCTION pgstac.pgstac_hash(data text)
 RETURNS text
 LANGUAGE sql
 IMMUTABLE PARALLEL SAFE STRICT
AS $function$
    SELECT encode(sha256(convert_to(data, 'UTF8')), 'hex');
$function$
;

